अंक time = 21 ; 
 अगर(time < 10 ) { 
 तंत्र.बाहर.प्रिंट("Good morning."); 
 }  
 या अगर(time < 20 ){ 
 तंत्र.बाहर.प्रिंट("Good day."); 
 } 
 या { 
 तंत्र.बाहर.प्रिंट("Good evening."); 
 }  
 // Outputs "Good evening."

अंक  day = 4;
 बदले  (day) {
   यदि 6:
     तंत्र.बाहर.प्रिंट("Today is Saturday");
     break;
   यदि 7:
     तंत्र.बाहर.प्रिंट("Today is Sunday");
     break;
   आम:
     तंत्र.बाहर.प्रिंट("Looking forward to the Weekend");
 }
 // Outputs "Looking forward to the Weekend"
